CREATE DATABASE IF NOT EXISTS lms_db CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci; USE lms_db;
CREATE TABLE users(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(100) NOT NULL,email VARCHAR(120) NOT NULL UNIQUE,password VARCHAR(255) NOT NULL,role ENUM('owner','admin','member','student') DEFAULT 'member',company ENUM('SECA','SASE','SBMA','SHS') DEFAULT 'SECA',phone VARCHAR(40),status ENUM('active','pending','blocked') DEFAULT 'active',student_id INT NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE courses(id INT AUTO_INCREMENT PRIMARY KEY,code VARCHAR(30) NOT NULL UNIQUE,title VARCHAR(150) NOT NULL,program ENUM('BSIT','BSCS','BSCompEngr','BSCivilEng','BSArchi','Psychology','Education','Accountancy','Tourism','ABM','STEM','HUMSS') NOT NULL,description TEXT,color VARCHAR(30) DEFAULT '#CDB4DB',created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE students(id INT AUTO_INCREMENT PRIMARY KEY,student_no VARCHAR(40) NOT NULL UNIQUE,full_name VARCHAR(150) NOT NULL,email VARCHAR(120) NOT NULL UNIQUE,program ENUM('BSIT','BSCS','BSCompEngr','BSCivilEng','BSArchi','Psychology','Education','Accountancy','Tourism','ABM','STEM','HUMSS') NOT NULL,course_id INT NULL,year_level VARCHAR(30) DEFAULT '1st Year',created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(course_id) REFERENCES courses(id) ON DELETE SET NULL);
CREATE TABLE lessons(id INT AUTO_INCREMENT PRIMARY KEY,course_id INT NOT NULL,title VARCHAR(150) NOT NULL,content TEXT NOT NULL,lesson_order INT DEFAULT 1,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(course_id) REFERENCES courses(id) ON DELETE CASCADE);
CREATE TABLE activities(id INT AUTO_INCREMENT PRIMARY KEY,course_id INT NOT NULL,title VARCHAR(150) NOT NULL,instructions TEXT NOT NULL,due_date DATE NULL,points INT DEFAULT 100,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(course_id) REFERENCES courses(id) ON DELETE CASCADE);
CREATE TABLE professors(id INT AUTO_INCREMENT PRIMARY KEY,full_name VARCHAR(150) NOT NULL,email VARCHAR(120) NOT NULL UNIQUE,department VARCHAR(120),avatar_color VARCHAR(30) DEFAULT '#BDE0FE');
CREATE TABLE course_professors(id INT AUTO_INCREMENT PRIMARY KEY,course_id INT NOT NULL,professor_id INT NOT NULL,UNIQUE KEY uq_cp(course_id,professor_id),FOREIGN KEY(course_id) REFERENCES courses(id) ON DELETE CASCADE,FOREIGN KEY(professor_id) REFERENCES professors(id) ON DELETE CASCADE);
CREATE TABLE enrollments(id INT AUTO_INCREMENT PRIMARY KEY,student_id INT NOT NULL,course_id INT NOT NULL,status ENUM('active','completed','dropped') DEFAULT 'active',UNIQUE KEY uq_enroll(student_id,course_id),FOREIGN KEY(student_id) REFERENCES students(id) ON DELETE CASCADE,FOREIGN KEY(course_id) REFERENCES courses(id) ON DELETE CASCADE);
CREATE TABLE grades(id INT AUTO_INCREMENT PRIMARY KEY,student_id INT NOT NULL,course_id INT NOT NULL,activity_id INT NULL,title VARCHAR(150) NOT NULL,score DECIMAL(5,2) DEFAULT 0,total DECIMAL(5,2) DEFAULT 100,remarks VARCHAR(255),created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(student_id) REFERENCES students(id) ON DELETE CASCADE,FOREIGN KEY(course_id) REFERENCES courses(id) ON DELETE CASCADE,FOREIGN KEY(activity_id) REFERENCES activities(id) ON DELETE SET NULL);
CREATE TABLE sent_activity_emails(id INT AUTO_INCREMENT PRIMARY KEY,activity_id INT NOT NULL,student_id INT NOT NULL,recipient_email VARCHAR(120) NOT NULL,subject VARCHAR(180) NOT NULL,status ENUM('preview','sent','failed') DEFAULT 'preview',error_message TEXT NULL,sent_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(activity_id) REFERENCES activities(id) ON DELETE CASCADE,FOREIGN KEY(student_id) REFERENCES students(id) ON DELETE CASCADE);
CREATE TABLE account_email_logs(id INT AUTO_INCREMENT PRIMARY KEY,user_id INT NULL,recipient_email VARCHAR(120) NOT NULL,subject VARCHAR(180) NOT NULL,email_type ENUM('registration_pending','account_approved','generic') DEFAULT 'generic',status ENUM('preview','sent','failed') DEFAULT 'preview',error_message TEXT NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE SET NULL);
